import { Diagram, HookEvent } from 'diagrams-js';
import { EC2 } from 'diagrams-js/aws/compute.js';
import { RDS } from 'diagrams-js/aws/database.js';
import { ELB } from 'diagrams-js/aws/network.js';

// Create a plugin that modifies node labels
const labelPrefixPlugin = () => ({
  name: 'label-prefix',
  version: '1.0.0',
  apiVersion: '1.0',
  runtimeSupport: { node: true, browser: true, deno: true, bun: true },
  capabilities: [
    {
      type: 'hook',
      hooks: [
        {
          event: HookEvent.NODE_CREATE,
          handler: async (data) => {
            data.node.label = '[AWS] ' + data.node.label;
            return data;
          },
        },
      ],
    },
  ],
});

// Create a plugin that adds colored edges
const coloredEdgePlugin = () => ({
  name: 'colored-edges',
  version: '1.0.0',
  apiVersion: '1.0',
  runtimeSupport: { node: true, browser: true, deno: true, bun: true },
  capabilities: [
    {
      type: 'hook',
      hooks: [
        {
          event: HookEvent.EDGE_CREATE,
          handler: async (data) => {
            // Modify the internal _attrs object directly
            data.edge._internalAttrs.color = 'blue';
            data.edge._internalAttrs.penwidth = '2';
            return data;
          },
        },
      ],
    },
  ],
});

const diagram = Diagram('Plugin Example');

// Register plugins before adding nodes
await diagram.registerPlugins([labelPrefixPlugin, coloredEdgePlugin]);

const lb = diagram.add(ELB('Load Balancer'));
const web = diagram.add(EC2('Web Server'));
const db = diagram.add(RDS('Database'));

// Connect nodes using chained syntax - edges will be modified by the plugin
lb.to(web).to(db);

const svg = await diagram.render();
document.getElementById('diagram').innerHTML = svg;
